function LGameTouch:Initialize()
	LxBaseMgr.Initialize(self)
	--{ k=TOUCH_OP, v={ k=touch_evt, v=func} }
	self._touchRegList = nil
	self._uiCamera = nil
	self._csSimpleTouch = nil

	---@region easy touch
	self._handlers = {}
	self._regHandlers = {}
	self._dirtyHandlers = {}
	---@endregion easy touch
end

function LGameTouch:DoAfterInitialize()
	self:TouchEnable(true)

	self._csSimpleTouch = PJXCenter.TouchMgr:GetSimpleTouch()

	---@region easy touch
	self:InitEasyTouch()
	---@region easy touch
end

function LGameTouch:Dispose()
	self._uiCamera = nil
	self:TouchUnRegisterAll()

	---@region easy touch
	self:DisposeEasyTouch()
	---@region easy touch

	LxBaseMgr.Dispose(self)
end
------------------------------------------------------------------
function LGameTouch:TouchEnable(b)
	PJXCenter.TouchMgr:EnableSimpleTouch(b)
end

