function LGameTouch:TouchUnRegisterAll()
	local touchRegList = self._touchRegList
	if not touchRegList then return end

	for k, v in pairs(touchRegList) do
		self:TouchUnRegister(k)
	end
	self._touchRegList = nil
end

function LGameTouch:TouchUnRegister(opType)
	local touchRegList = self._touchRegList
	if not touchRegList then return end
	
	local opRegList = touchRegList[opType]
	if not opRegList then return end
	
	for k, v in pairs(opRegList) do
		--self:TouchEventRemove(k, v)
		self:UnRegisterCallFunc(opType,k)
		v = nil
	end
	opRegList = nil
	touchRegList[opType] = nil
end

function LGameTouch:TouchUnRegisterEx(opType,evtType,func)
	if not (evtType and evtType and func) then return end

	local touchRegList = self._touchRegList
	if not touchRegList then return end

	local opRegList = touchRegList[opType]
	if not opRegList then return end

	local list = opRegList[evtType]
	if not list then return end

	table.removeidata(list,func)
	if #list > 0 then return end

	opRegList[evtType] = nil
	self:UnRegisterCallFunc(opType,evtType)
end

function LGameTouch:TouchRegister(opType, evtType, func)
	if not evtType then return end

	local touchRegList = self._touchRegList
	if not touchRegList then
		touchRegList = {}
		self._touchRegList = touchRegList
	end

	local opRegList = touchRegList[opType]
	if not opRegList then
		opRegList = {}
		touchRegList[opType] = opRegList
	end

	local list = opRegList[evtType]
	if not list then
		list = {}
		opRegList[evtType] = list
	end

	table.insert(list,func)
	self:RegisterCallFunc(opType,evtType)


	--if (not opRegList[evtType]) then
	--	if (self:TouchEventRecv(evtType, func)) then
	--		opRegList[evtType] = func
	--	end
	--else
	--	LogError("touch evt register or forgot unregister, op=" .. tostring(opType) .. ", evt=" .. tostring(evtType))
	--end
end

function LGameTouch:CallEventFun(opType,eventType,...)
	local touchRegList = self._touchRegList
	if not touchRegList then return end

	local opRegList = touchRegList[opType]
	if not opRegList then return end

	local funcList = opRegList[eventType]
	if not funcList then return end

	local tempList = {}
	for k,v in ipairs(funcList) do
		table.insert(tempList,v)
	end

	for k= #tempList,1,-1 do
		local func = tempList[k]
		if func then
			func(...)
		end
	end
end

function LGameTouch:RegisterCallFunc(opType,eventType)
	local list = self._callFuncList
	if not list then
		list = {}
		self._callFuncList =list
	end

	local tempList =list[opType]
	if not tempList then
		tempList = {}
		list[opType] = tempList
	end

	local func = tempList[eventType]
	if func then  ---已注册过
		return
	end

	func = function(...)
		self:CallEventFun(opType,eventType,...)
	end

	tempList[eventType] = func

	self:TouchEventRecv(eventType, func)
	return func
end


function LGameTouch:UnRegisterCallFunc(opType,eventType)
	local list = self._callFuncList
	if not list then return end

	local tempList =list[opType]
	if not tempList then return end

	local func = tempList[eventType]
	if not func then return end

	tempList[eventType] = nil
	---注册过
	self:TouchEventRemove(eventType, func)
end

