	[LGameTouch.TOUCH_EVT_START] = "on_TouchStart",
	[LGameTouch.TOUCH_EVT_MOVE] = "on_TouchMove",
	[LGameTouch.TOUCH_EVT_END] = "on_TouchEnd",
	[LGameTouch.TOUCH_EVT_CANCEL] = "on_TouchCancel",
}

function LGameTouch:TouchEventRecv(evtType, func)
	local simpleTouch = self._csSimpleTouch
	local csFuncName = LGameTouch.TOUCH_EVT_FUNC_NAME_LIST[evtType]
	if string.isempty(csFuncName) then return false end

	simpleTouch[csFuncName] = simpleTouch[csFuncName] + func
	return true
end

function LGameTouch:TouchEventRemove(evtType, func)
	local simpleTouch = self._csSimpleTouch
	local csFuncName = LGameTouch.TOUCH_EVT_FUNC_NAME_LIST[evtType]
	if string.isempty(csFuncName) then return false end

	simpleTouch[csFuncName] = simpleTouch[csFuncName] - func
	return true
end
