function LGameTouch:DisposeEasyTouch()
	if self._easyTouchTimer then
		LxTimer.LoopTimeStop(self._easyTouchTimer)
		self._easyTouchTimer = nil
	end
	local handlers = self._handlers
	if handlers then
		for k,v in pairs(self._handlers) do
			handlers[k] = nil
			for m,n in ipairs(v) do
				n.removed = true
				n.func = nil
				n.target = nil
			end
		end
	end

	local regHandlers = self._regHandlers
	if regHandlers then
		for eventName,eventHandler in pairs(regHandlers) do
			SimpleTouch[eventName] = SimpleTouch[eventName] - eventHandler
			regHandlers[eventName] = nil
		end
	end
end

function LGameTouch:InitEasyTouch()
    local touchObj = CS.FindObject("[Touch]")
	if not touchObj then
		touchObj = CS.NewObject("[Touch]")
		touchObj = touchObj.gameObject
	else
		touchObj = touchObj.gameObject
	end
	local typeofSimpleTouch = typeof(SimpleTouch)
    local touchInst = touchObj:GetComponent(typeofSimpleTouch)
    if not touchInst then
        touchInst = touchObj:AddComponent(typeofSimpleTouch)
    end
    touchInst.pickableLayers = 0 --touchLayersMask
    touchInst.autoSelect = false
    touchInst.enable = false
    self._easyTouchInst = touchInst
    self._easyTouchEnabled = false
	self._easyTouchTimer = LxTimer.LoopTimeCall(function()
		self:OnUpdate()
	end, 1)
end

function LGameTouch:AddTouch(touchName, func, target)
	local funcList = self._handlers[touchName]
	if not funcList then
		funcList = {}
		self._handlers[touchName] = funcList
	end
	table.insert(funcList, {func = func, target = target})
	if not self._regHandlers[touchName] then
		self:InternalAddListener(touchName)
		self:UpdateTouchState()
	end
end

function LGameTouch:RemoveTouch(touchName, func, target)
	local funcList = self._handlers[touchName]
	if not funcList then return end

	for k,v in ipairs(funcList) do
		if v.func == func and v.target == target then
			v.func = nil
			v.target = nil
			v.removed = true
			self._dirtyHandlers[touchName] = true
			break
		end
	end
end

function LGameTouch:OnUpdate()
	if self._isDisposed then return end

	for eventName,_v in pairs(self._dirtyHandlers) do
		self._dirtyHandlers[eventName] = nil
		local funcList = self._handlers[eventName]
		if funcList then
			for k=#funcList,1,-1 do
				local func = funcList[k]
				if func.removed then
					table.remove(funcList, k)
				end
			end
			if #funcList == 0 then
				self:InternalRemoveListener(eventName)
			end
		end
	end
	if self._bUpdateState then
		self:UpdateTouchState()
	end
end

function LGameTouch:UpdateTouchState()
	self._bUpdateState = nil
	local bEmpty = table.isempty(self._regHandlers)
	if self._easyTouchEnabled then
		if bEmpty then
			self._easyTouchInst.enable = false
			self._easyTouchEnabled = false
		end
	else
		if not bEmpty then
			self._easyTouchInst.enable = true
			self._easyTouchEnabled = true
		end
	end

end

function LGameTouch:OnEventHandler(eventName, gesture)
	--if LOG_INFO_ENABLED then
	--    printInfo("Touch", "--->>> on touch handler(name=%s)" ,eventName)
	--end
	local funcList = self._handlers[eventName]
	if not funcList then return end

	local removeList = {}
	local bRemove = false
	for k,v in ipairs(funcList) do
		if not v.removed then
			if v.target ~= nil then
				v.func(v.target, gesture)
			else
				v.func(gesture)
			end
		else
			bRemove = true
			table.insert(removeList, k)
		end
	end

	if bRemove then
		self._dirtyHandlers[eventName] = nil
		for k=#removeList, 1, -1 do
			table.remove(funcList, removeList[k])
		end
		if #funcList == 0 then
			self:InternalRemoveListener(eventName)
		end
	end
end

function LGameTouch:InternalAddListener(eventName)
	local eventHandler = function(gesture)
		self:OnEventHandler(eventName, gesture)
	end
	self._regHandlers[eventName] = eventHandler
	SimpleTouch[eventName] = SimpleTouch[eventName] + eventHandler
end

function LGameTouch:InternalRemoveListener(eventName)
	self._bUpdateState = true
	local eventHandler = self._regHandlers[eventName]
	if eventHandler then
		SimpleTouch[eventName] = SimpleTouch[eventName] - eventHandler
		self._regHandlers[eventName] = nil
	end
end
----@endregion easy touch

return LGameTouch

